INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, "クリスティーナ！\nあなたはいったいどの面下げて\n私たちの前に……", 8, 0, 103731, 506, 1, 11, 0, 506013, 0.5);
