INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, "確かに沢山の人が来られてますね。\nプロデューサーさんも\n楽しそうにしてました。", 7, 0, 104211, 515, 1, 11, 0, 515047, 0.5);
