INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, "こんなに人が集まったのも\nきっとキミの人望だね。", 6, 0, 102931, 515, 1, 11, 0, 515052, 0.5);
