INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, "それだチエル君。\nノブレス・オブリージュ──\n大雑把に換言すれば、アキノ君は我々に\n金銭的援助をほどこす義務がある。", 8, 0, 111031, 517, 1, 11, 0, 517037, 0.5);
